#!/usr/bin/env node
/**
 * scripts/prompt-ref.mjs -- Phase/Wave Reference Resolver
 *
 * Looks up prompt folders by phase number, folder prefix, or free-text search.
 * Source of truth: docs/qa/phase-index.json (regenerated by pnpm qa:phase-index).
 *
 * Usage:
 *   node scripts/prompt-ref.mjs --phase 284
 *   node scripts/prompt-ref.mjs --prefix 291
 *   node scripts/prompt-ref.mjs --search "billing grounding"
 *   node scripts/prompt-ref.mjs --phase 37      # shows 37, 37B, 37C etc.
 *   node scripts/prompt-ref.mjs --wave 36
 *
 * Flags:
 *   --json    Output as JSON instead of formatted text
 *   --regen   Regenerate phase-index.json before lookup
 */

import { readFileSync, existsSync } from 'node:fs';
import { resolve } from 'node:path';
import { execSync } from 'node:child_process';

const ROOT = process.cwd();
const INDEX_PATH = resolve(ROOT, 'docs/qa/phase-index.json');

const args = process.argv.slice(2);

function getArg(flag) {
  const idx = args.indexOf(flag);
  return idx >= 0 && args[idx + 1] ? args[idx + 1] : null;
}
const hasFlag = (f) => args.includes(f);

// ── Regenerate if requested or missing ──

if (hasFlag('--regen') || !existsSync(INDEX_PATH)) {
  console.log('Regenerating phase-index.json...');
  try {
    execSync('node scripts/build-phase-index.mjs', { cwd: ROOT, stdio: 'inherit' });
  } catch {
    console.error('ERROR: Failed to regenerate phase-index.json');
    process.exit(1);
  }
}

// ── Load index ──

if (!existsSync(INDEX_PATH)) {
  console.error('ERROR: docs/qa/phase-index.json not found.');
  console.error('Run: pnpm qa:phase-index');
  process.exit(1);
}

const raw = readFileSync(INDEX_PATH, 'utf-8');
const index = JSON.parse(raw.charCodeAt(0) === 0xfeff ? raw.slice(1) : raw);
const phases = index.phases;

// ── Lookup modes ──

const phaseArg = getArg('--phase');
const prefixArg = getArg('--prefix');
const searchArg = getArg('--search');
const waveArg = getArg('--wave');
const jsonOutput = hasFlag('--json');

if (!phaseArg && !prefixArg && !searchArg && !waveArg) {
  console.log(`
Phase/Wave Reference Resolver
==============================
Usage:
  node scripts/prompt-ref.mjs --phase <number>   Lookup by phase number (e.g. 284, 37, 37C)
  node scripts/prompt-ref.mjs --prefix <number>  Lookup by folder prefix (e.g. 291)
  node scripts/prompt-ref.mjs --search <text>    Free-text search across titles and folders
  node scripts/prompt-ref.mjs --wave <number>    Lookup by wave number

Flags:
  --json    Output as JSON
  --regen   Rebuild index before search

Source: docs/qa/phase-index.json (${index.phaseCount} phases indexed)
  `);
  process.exit(0);
}

/**
 * Extract wave metadata from folder name.
 */
function extractWave(folder) {
  const waveMatch = folder.match(/W(\d+)-P(\d+)/);
  if (waveMatch) {
    return { wave: parseInt(waveMatch[1], 10), position: parseInt(waveMatch[2], 10) };
  }
  const auditMatch = folder.match(/WAVE-(\d+)/);
  if (auditMatch) {
    return { wave: parseInt(auditMatch[1], 10), position: null };
  }
  return null;
}

/**
 * Extract folder prefix number.
 */
function extractPrefix(folder) {
  const m = folder.match(/^(\d+)/);
  return m ? parseInt(m[1], 10) : null;
}

/**
 * Format a single result for display.
 */
function formatResult(phase) {
  const wave = extractWave(phase.folder);
  const prefix = extractPrefix(phase.folder);
  const lines = [
    `  Phase:    ${phase.phaseNumber}`,
    `  Title:    ${phase.title}`,
    `  Folder:   prompts/${phase.folder}`,
    `  Prefix:   ${prefix}`,
  ];
  if (wave) {
    lines.push(`  Wave:     ${wave.wave}${wave.position !== null ? ` (position ${wave.position})` : ''}`);
  }
  if (phase.implementFiles.length > 0) {
    lines.push(`  Implement: ${phase.implementFiles.join(', ')}`);
  }
  if (phase.verifyFiles.length > 0) {
    lines.push(`  Verify:    ${phase.verifyFiles.join(', ')}`);
  }
  if (phase.routes.length > 0) {
    lines.push(`  Routes:    ${phase.routes.slice(0, 5).join(', ')}${phase.routes.length > 5 ? ` (+${phase.routes.length - 5} more)` : ''}`);
  }
  if (phase.rpcs.length > 0) {
    lines.push(`  RPCs:      ${phase.rpcs.slice(0, 5).join(', ')}${phase.rpcs.length > 5 ? ` (+${phase.rpcs.length - 5} more)` : ''}`);
  }
  return lines.join('\n');
}

function toJsonResult(phase) {
  return {
    phaseNumber: phase.phaseNumber,
    title: phase.title,
    folder: phase.folder,
    prefix: extractPrefix(phase.folder),
    wave: extractWave(phase.folder),
    implementFiles: phase.implementFiles,
    verifyFiles: phase.verifyFiles,
    routes: phase.routes,
    rpcs: phase.rpcs,
    uiComponents: phase.uiComponents,
    filesTouched: phase.filesTouched,
  };
}

function outputResults(results, label) {
  if (results.length === 0) {
    if (jsonOutput) {
      console.log(JSON.stringify({ query: label, matches: [] }, null, 2));
    } else {
      console.log(`\nNo matches for: ${label}`);
    }
    return;
  }

  if (jsonOutput) {
    console.log(JSON.stringify({ query: label, matches: results.map(toJsonResult) }, null, 2));
  } else {
    console.log(`\n${results.length} match(es) for: ${label}\n`);
    for (let i = 0; i < results.length; i++) {
      if (i > 0) console.log('  ---');
      console.log(formatResult(results[i]));
    }
    console.log();
  }
}

// ── Execute lookup ──

if (phaseArg) {
  // Exact match first, then prefix match (e.g. --phase 37 matches 37, 37B, 37C)
  const exact = phases.filter((p) => p.phaseNumber === phaseArg);
  const prefixMatches = phases.filter(
    (p) => p.phaseNumber !== phaseArg && p.phaseNumber.startsWith(phaseArg)
  );
  const all = [...exact, ...prefixMatches];

  if (all.length === 0) {
    // Subphase fallback: "15B" -> try base "15"
    const subMatch = phaseArg.match(/^(\d+)([A-Za-z].*)$/);
    if (subMatch) {
      const basePhase = subMatch[1];
      const baseExact = phases.filter((p) => p.phaseNumber === basePhase);
      const basePrefix = phases.filter(
        (p) => p.phaseNumber !== basePhase && p.phaseNumber.startsWith(basePhase)
      );
      const baseAll = [...baseExact, ...basePrefix];
      if (baseAll.length > 0) {
        if (!jsonOutput) {
          console.log(`\n  Resolved by base phase: ${basePhase} (from ${phaseArg})\n`);
        }
        outputResults(baseAll, `phase ${phaseArg} (via base ${basePhase})`);
      } else {
        outputResults([], `phase ${phaseArg}`);
      }
    } else {
      outputResults([], `phase ${phaseArg}`);
    }
  } else {
    outputResults(all, `phase ${phaseArg}`);
  }
}

if (prefixArg) {
  const target = parseInt(prefixArg, 10);
  const matches = phases.filter((p) => extractPrefix(p.folder) === target);
  outputResults(matches, `prefix ${prefixArg}`);
}

if (waveArg) {
  const target = parseInt(waveArg, 10);
  const matches = phases.filter((p) => {
    const w = extractWave(p.folder);
    return w && w.wave === target;
  });
  outputResults(matches, `wave ${waveArg}`);
}

if (searchArg) {
  const terms = searchArg.toLowerCase().split(/\s+/);
  const matches = phases.filter((p) => {
    const corpus = [
      p.title,
      p.folder,
      p.phaseNumber,
      ...p.routes,
      ...p.rpcs,
      ...p.filesTouched,
    ]
      .join(' ')
      .toLowerCase();
    return terms.every((t) => corpus.includes(t));
  });
  outputResults(matches, `search "${searchArg}"`);
}
